diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 48055ad6ea7e..4c61f9fff161 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -314,7 +314,7 @@ class SimplifyCFGOpt {
                                  const DataLayout &DL);
   bool simplifySwitchOnSelect(SwitchInst *SI, SelectInst *Select);
   bool simplifyIndirectBrOnSelect(IndirectBrInst *IBI, SelectInst *SI);
-  bool turnSwitchRangeIntoICmp(SwitchInst *SI, IRBuilder<> &Builder);
+  bool turnSwitchRangeIntoICmp(SwitchInst *SI, IRBuilder<> &Builder, bool AllowGeneralPath);

 public:
   SimplifyCFGOpt(const TargetTransformInfo &TTI, DomTreeUpdater *DTU,
@@ -5773,7 +5773,8 @@ static void createUnreachableSwitchDefault(SwitchInst *Switch,
 /// Switches with more than 2 destinations are ignored.
 /// Switches with 1 destination are also ignored.
 bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
-                                             IRBuilder<> &Builder) {
+                                             IRBuilder<> &Builder,
+                                             bool AllowGeneralPath) {
   assert(SI->getNumCases() > 1 && "Degenerate switch?");

   bool HasDefault = !SI->defaultDestUnreachable();
@@ -5812,19 +5813,78 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
   assert(!CasesB.empty() && "There must be non-default cases.");
   assert(!CasesA.empty() || HasDefault);

+
   // Figure out if one of the sets of cases form a contiguous range.
   SmallVectorImpl<ConstantInt *> *ContiguousCases = nullptr;
   BasicBlock *ContiguousDest = nullptr;
   BasicBlock *OtherDest = nullptr;
-  if (!CasesA.empty() && casesAreContiguous(CasesA)) {
-    ContiguousCases = &CasesA;
-    ContiguousDest = DestA;
-    OtherDest = DestB;
-  } else if (casesAreContiguous(CasesB)) {
-    ContiguousCases = &CasesB;
-    ContiguousDest = DestB;
-    OtherDest = DestA;
-  } else
+  SmallVector<ConstantInt *, 16> ComplementCases;
+
+  // Check if one of the sets of explicit cases forms a contiguous range.
+  // This general path may lose information about impossible switch values,
+  // so only do it when AllowGeneralPath is set.
+  if (AllowGeneralPath) {
+    if (!CasesA.empty() && casesAreContiguous(CasesA)) {
+      ContiguousCases = &CasesA;
+      ContiguousDest = DestA;
+      OtherDest = DestB;
+    } else if (casesAreContiguous(CasesB)) {
+      ContiguousCases = &CasesB;
+      ContiguousDest = DestB;
+      OtherDest = DestA;
+    }
+  }
+
+  // If no contiguous set found and there is a default destination, check if
+  // the complement of the explicit cases within the known range of the
+  // condition forms a contiguous range. This path requires range information
+  // and is always safe.
+  if (!ContiguousCases && HasDefault) {
+    ConstantRange CR = computeConstantRange(SI->getCondition(),
+                                            /*ForSigned=*/false,
+                                            /*UseInstrInfo=*/true,
+                                            Options.AC, SI);
+    if (!CR.isFullSet()) {
+      // Collect all explicit case values.
+      SmallVector<ConstantInt *, 16> AllCases;
+      AllCases.assign(CasesA.begin(), CasesA.end());
+      AllCases.append(CasesB.begin(), CasesB.end());
+      array_pod_sort(AllCases.begin(), AllCases.end(), constantIntSortPredicate);
+
+      // Build the complement: values in [CR.getLower(), CR.getUpper())
+      // that are not in AllCases.
+      const APInt &Lower = CR.getLower();
+      const APInt &Upper = CR.getUpper();
+
+      // Check range size to avoid excessive compile time.
+      APInt RangeSize = Upper - Lower;
+      if (RangeSize.ule(256)) {
+        APInt Cur = Lower;
+        for (auto *C : reverse(AllCases)) {
+          const APInt &CaseVal = C->getValue();
+          while (Cur.ult(CaseVal)) {
+            ComplementCases.push_back(ConstantInt::get(SI->getContext(), Cur));
+            ++Cur;
+          }
+          if (Cur.eq(CaseVal))
+            ++Cur;
+        }
+        while (Cur.ult(Upper)) {
+          ComplementCases.push_back(ConstantInt::get(SI->getContext(), Cur));
+          ++Cur;
+        }
+
+        if (!ComplementCases.empty() && casesAreContiguous(ComplementCases)) {
+          ContiguousCases = &ComplementCases;
+          // Values not in explicit cases go to the default destination (DestA).
+          ContiguousDest = DestA;
+          OtherDest = DestB;
+        }
+      }
+    }
+  }
+
+  if (!ContiguousCases)
     return false;

   // Start building the compare and branch.
@@ -7833,7 +7893,7 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
   // Try to transform the switch into an icmp and a branch.
   // The conversion from switch to comparison may lose information on
   // impossible switch values, so disable it early in the pipeline.
-  if (Options.ConvertSwitchRangeToICmp && turnSwitchRangeIntoICmp(SI, Builder))
+  if (turnSwitchRangeIntoICmp(SI, Builder, Options.ConvertSwitchRangeToICmp))
     return requestResimplify();

   // Remove unreachable cases.

messages.reasoning_content:
Let me understand the task. We have a missed optimization where a switch instruction with a range-annotated argument should be turned into an icmp-based branch. Let me first look at the issue details and then examine the relevant source code.

The source program:
```llvm
define i32 @test(i8 range(i8 0, 6) %arg) {
  switch i8 %arg, label %else [
    i8 0, label %if
    i8 4, label %if
    i8 5, label %if
  ]

if:
  ret i32 0

else:
  ret i32 1
}
```

The expected optimized program:
```llvm
define i32 @test(i8 %arg) {
  %add = add i8 %arg, -1
  %cmp2 = icmp ult i8 %add, 3
  br i1 %cmp2, label %else, label %if

if:
  ret i32 0

else:
  ret i32 1
}
```

So the switch cases are: 0, 4, 5 → all go to `if`. The default goes to `else`. The range of `%arg` is [0, 6), i.e., 0-5. The switch covers 0, 4, 5 for the `if` branch, meaning only values 1, 2, 3 go to `else`. So the expected optimization transforms this to an icmp: if arg is 1, 2, or 3 (i.e., arg-1 < 3), go to else; otherwise go to if.

The localization says to look at `turnSwitchRangeIntoICmp` in `SimplifyCFG.cpp`. Let me start there.

