      SmallVector<ConstantInt *, 16> AllCases;
      AllCases.assign(CasesA.begin(), CasesA.end());
      AllCases.append(CasesB.begin(), CasesB.end());
      array_pod_sort(AllCases.begin(), AllCases.end(), constantIntSortPredicate);

      // Build the complement: values in [CR.getLower(), CR.getUpper())
      // that are not in AllCases.
      const APInt &Lower = CR.getLower();
      const APInt &Upper = CR.getUpper();

      // Check range size to avoid excessive compile time.
      APInt RangeSize = Upper - Lower;
      if (RangeSize.ule(256)) {
