        for (auto *C : reverse(AllCases)) {
          const APInt &CaseVal = C->getValue();
          while (Cur.ult(CaseVal)) {
            ComplementCases.push_back(ConstantInt::get(SI->getContext(), Cur));
            ++Cur;
          }
          if (Cur.eq(CaseVal))
            ++Cur;
        }
        while (Cur.ult(Upper)) {
          ComplementCases.push_back(ConstantInt::get(SI->getContext(), Cur));
